text:
@while $left-index <= $left-length and $right-index <= $right-length
		$left-value: list.nth($left, $left-index)
		$right-value: list.nth($right, $right-index)

		@if meta.call($compare, $left-value, $right-value, $center) < 0
			$result: list.append($result, $left-value)
			$left-index: $left-index + 1

		@else
			$result: list.append($result, $right-value)
			$right-index: $right-index + 1

li.toctree-l#{$toc_level}
        a
          @extend %toctree_link_color
        &.current
          > a
            padding: ($gutter / 4) ($gutter * ($toc_level - 1 + 0.5))

          li.toctree-l#{$toc_level + 1}  > a
            @extend %display_current_toctree_element
            padding: ($gutter / 4) ($gutter * ($toc_level + 0.5))
            padding-right: $gutter
        a:hover button.toctree-expand
          @extend %toctree_hover_link_color

@if $scale-grid-style == traditional
        @for $i from 1 through $units
          $column-sum: ms($i, 100%, $column-ratio)
          $grid-sum: $column-sum + $grid-sum
          $return: $column-sum
          @if $grid-sum > 100%
            $return: 0%
            @if $column-short == false
              $column-short: $i
          @if $i == $columns
            @if $grid-sum < 100%
              $return: 100% - $grid-sum + $column-sum
          @if $column-short == $i
            $return: 100% - $grid-sum + $column-sum

@if $scale-grid-style == incremental
        @for $i from 1 through $units
          $return: ms(-1, $column-sum, (1 / $column-ratio))
          $column-sum: $column-sum - $return
          $grid-sum: $return + $grid-sum
          @if $grid-sum > 100%
            $return: 0%
            @if $column-short == false
              $column-short: $i
          @if $i == $columns
            @if $grid-sum < 100%
              $return: $column-sum
          @if $column-short == $i
            $return: $column-sum

@else if type-of($gutter) == "map"
    @if $expectWithVertical == false
      $gr: sassyAutoGutterFallback(map-get($gutter, "right"), $sgh)
      $gl: sassyAutoGutterFallback(map-get($gutter, "left"), $sgh)
    @else
      $gt: sassyAutoGutterFallback(map-get($gutter, "top"), $sgv) / 2
      $gr: sassyAutoGutterFallback(map-get($gutter, "right"), $sgh) / 2
      $gb: sassyAutoGutterFallback(map-get($gutter, "bottom"), $sgv) / 2
      $gl: sassyAutoGutterFallback(map-get($gutter, "left"), $sgh) / 2

&--#{$modifier}
          @if $modifier == 'xs'
            margin-#{$position}: $spacing-xs
          @else if $modifier == 's'
            margin-#{$position}: $spacing-sm
          @else if $modifier == 'm'
            margin-#{$position}: $spacing-md
          @else if $modifier == 'l'
            margin-#{$position}: $spacing-lg
          @else if $modifier == 'xl'
            margin-#{$position}: $spacing-xl
          @else if $modifier == 'hg'
            margin-#{$position}: $spacing-hg
          @else if $modifier == 'none'
            margin-#{$position}: 0

&--#{$modifier}
          @if $modifier == 'xs'
            margin-#{$position}: $spacing-xs !important
          @else if $modifier == 's'
            margin-#{$position}: $spacing-sm !important
          @else if $modifier == 'm'
            margin-#{$position}: $spacing-md !important // 12px -> 16
          @else if $modifier == 'l'
            margin-#{$position}: $spacing-lg !important // 16 -> 24
          @else if $modifier == 'xl'
            margin-#{$position}: $spacing-xl !important // 20 -> 32
          @else if $modifier == 'none'
            margin-#{$position}: 0 !important

li.toctree-l#{$toc_level}
        a
          @extend %toctree_link_color
        &.current
          > a
            padding: ($gutter / 4) ($gutter * ($toc_level - 1 + 0.5))

          li.toctree-l#{$toc_level + 1}  > a
            @extend %display_current_toctree_element
            padding: ($gutter / 4) ($gutter * ($toc_level + 0.5))
            padding-right: $gutter
        a:hover span.toctree-expand
          @extend %toctree_hover_link_color

@keyframes q-spin
  0%
    transform: rotate3d(0, 0, 1, 0deg) #{"/* rtl:ignore */"}
  25%
    transform: rotate3d(0, 0, 1, 90deg) #{"/* rtl:ignore */"}
  50%
    transform: rotate3d(0, 0, 1, 180deg) #{"/* rtl:ignore */"}
  75%
    transform: rotate3d(0, 0, 1, 270deg) #{"/* rtl:ignore */"}
  100%
    transform: rotate3d(0, 0, 1, 359deg) #{"/* rtl:ignore */"}
